+            state.drill_cursor = 0;
+        }
+        self.sync_insights_heatmap_selection();
+    }
+
+    fn exit_insights_heatmap_drill(&mut self) -> bool {
+        let Some(state) = self.insights_heatmap.as_mut() else {
+            return false;
+        };
+        if !state.drill_active {
+            return false;
+        }
+
+        state.drill_active = false;
+        state.drill_cursor = 0;
+        self.sync_insights_heatmap_selection();
+        true
+    }
